#if UNITY_EDITOR
using System;
using UnityEditor;
using UnityEngine;

/// <summary>
/// Editor customizado do NpcController. Desenha a lista de eventos com
/// foldouts, e para as listas polimórficas "Conditions" e "Actions" de cada
/// evento (e para "Condições de Visibilidade") usa PolymorphicListDrawer, que
/// mostra um botão "+ Adicionar..." listando (via reflexão) todas as subclasses
/// de NpcCondition / NpcAction encontradas no projecto — incluindo novas que
/// sejam adicionadas no futuro, sem precisar de tocar neste editor.
/// </summary>
[CustomEditor(typeof(NpcController))]
public class NpcControllerEditor : Editor
{
    private SerializedProperty _eventsProp;

    private void OnEnable()
    {
        _eventsProp = serializedObject.FindProperty("events");
    }

    public override void OnInspectorGUI()
    {
        serializedObject.Update();

        DrawPropertiesExcluding(serializedObject, "m_Script", "events", "visibilityConditions", "localVariables");

        EditorGUILayout.Space();
        GameVariableListDrawer.Draw(serializedObject.FindProperty("localVariables"), "Variáveis Locais (Etapa 8)");

        EditorGUILayout.Space();
        PolymorphicListDrawer.Draw(serializedObject, serializedObject.FindProperty("visibilityConditions"), "Condições de Visibilidade (Etapa 7)", typeof(NpcCondition), "Adicionar Condição de Visibilidade");

        EditorGUILayout.Space();
        EditorGUILayout.LabelField("Eventos do NPC", EditorStyles.boldLabel);

        int removeIndex = -1;

        for (int i = 0; i < _eventsProp.arraySize; i++)
        {
            if (DrawEvent(i)) removeIndex = i;
        }

        if (removeIndex >= 0)
            _eventsProp.DeleteArrayElementAtIndex(removeIndex);

        EditorGUILayout.Space();

        if (GUILayout.Button("+ Adicionar Evento"))
            AddNewEvent();

        serializedObject.ApplyModifiedProperties();
    }

    // ---------------- Eventos ----------------

    /// <summary>Desenha um evento. Devolve true se o utilizador pediu para o remover.</summary>
    private bool DrawEvent(int index)
    {
        var eventProp = _eventsProp.GetArrayElementAtIndex(index);
        var labelProp = eventProp.FindPropertyRelative("label");

        bool removeRequested = false;

        EditorGUILayout.BeginVertical("box");
        EditorGUILayout.BeginHorizontal();

        string title = string.IsNullOrEmpty(labelProp.stringValue) ? $"Evento {index}" : labelProp.stringValue;
        eventProp.isExpanded = EditorGUILayout.Foldout(eventProp.isExpanded, title, true);

        GUILayout.FlexibleSpace();

        if (Application.isPlaying)
        {
            var activeProp = eventProp.FindPropertyRelative("isActive");
            EditorGUILayout.LabelField(activeProp.boolValue ? "Activo" : "Inactivo", GUILayout.Width(60));
        }

        if (GUILayout.Button("Remover", GUILayout.Width(70)))
            removeRequested = true;

        EditorGUILayout.EndHorizontal();

        if (eventProp.isExpanded && !removeRequested)
        {
            EditorGUI.indentLevel++;

            EditorGUILayout.PropertyField(eventProp.FindPropertyRelative("eventId"));
            EditorGUILayout.PropertyField(labelProp);
            EditorGUILayout.PropertyField(eventProp.FindPropertyRelative("priority"));
            EditorGUILayout.PropertyField(eventProp.FindPropertyRelative("interactionType"));
            EditorGUILayout.PropertyField(eventProp.FindPropertyRelative("interactionRange"));
            EditorGUILayout.PropertyField(eventProp.FindPropertyRelative("startActive"));
            EditorGUILayout.PropertyField(eventProp.FindPropertyRelative("overrideSprite"));

            EditorGUILayout.Space();
            PolymorphicListDrawer.Draw(serializedObject, eventProp.FindPropertyRelative("conditions"), "Condições", typeof(NpcCondition), "Adicionar Condição");

            EditorGUILayout.Space();
            PolymorphicListDrawer.Draw(serializedObject, eventProp.FindPropertyRelative("actions"), "Ações", typeof(NpcAction), "Adicionar Ação");

            // Validação: avisar se Action_RescueNpc existe sem Action_Autosave depois dela.
            ValidateRescueNpcAutosave(eventProp.FindPropertyRelative("actions"));

            EditorGUILayout.Space();
            EditorGUILayout.PropertyField(eventProp.FindPropertyRelative("deactivateOnComplete"));
            EditorGUILayout.PropertyField(eventProp.FindPropertyRelative("activateEventIdOnComplete"));

            EditorGUI.indentLevel--;
        }

        EditorGUILayout.EndVertical();

        return removeRequested;
    }

    // ---------------- Validação ----------------

    /// <summary>
    /// Verifica se a lista de acções contém Action_RescueNpc sem Action_Autosave
    /// a seguir. Mostra um HelpBox de aviso no Inspector caso seja omitida.
    /// </summary>
    private static void ValidateRescueNpcAutosave(SerializedProperty actionsProp)
    {
        if (actionsProp == null || actionsProp.arraySize == 0) return;

        int rescueIndex = -1;
        bool hasAutosaveAfterRescue = false;

        for (int i = 0; i < actionsProp.arraySize; i++)
        {
            var elem = actionsProp.GetArrayElementAtIndex(i);
            string typeName = elem.managedReferenceFullTypename;

            if (typeName != null && typeName.EndsWith("Action_RescueNpc"))
            {
                rescueIndex = i;
                hasAutosaveAfterRescue = false; // reset: pode haver várias rescues
            }
            else if (rescueIndex >= 0 && typeName != null && typeName.EndsWith("Action_Autosave"))
            {
                hasAutosaveAfterRescue = true;
            }
        }

        if (rescueIndex >= 0 && !hasAutosaveAfterRescue)
        {
            EditorGUILayout.HelpBox(
                "Este evento tem Action_RescueNpc mas não tem Action_Autosave depois dela.\n" +
                "Adicionar Action_Autosave após Action_RescueNpc para não perder o progresso.",
                MessageType.Warning);
        }
    }

    private void AddNewEvent()
    {
        int newIndex = _eventsProp.arraySize;
        _eventsProp.arraySize++;

        var newEvent = _eventsProp.GetArrayElementAtIndex(newIndex);

        newEvent.FindPropertyRelative("eventId").stringValue = "evento_" + Guid.NewGuid().ToString("N").Substring(0, 8);
        newEvent.FindPropertyRelative("label").stringValue = "Novo Evento";
        newEvent.FindPropertyRelative("priority").intValue = 0;
        newEvent.FindPropertyRelative("interactionType").enumValueIndex = (int)NpcInteractionType.Button;
        newEvent.FindPropertyRelative("interactionRange").floatValue = 0f;
        newEvent.FindPropertyRelative("startActive").boolValue = true;
        newEvent.FindPropertyRelative("overrideSprite").objectReferenceValue = null;
        newEvent.FindPropertyRelative("deactivateOnComplete").boolValue = false;
        newEvent.FindPropertyRelative("activateEventIdOnComplete").stringValue = string.Empty;
        newEvent.isExpanded = true;

        newEvent.FindPropertyRelative("conditions").arraySize = 0;
        newEvent.FindPropertyRelative("actions").arraySize = 0;
    }
}
#endif
